function sf_ai_script_text($v, string $fallback = 'Not set'): string { $t = trim((string)($v ?? '')); return $t === '' ? $fallback : $t; }
function sf_ai_script_snip($v, int $n = 160, string $fallback = 'Not set'): string { $t = sf_ai_script_text($v, $fallback); return strlen($t) > $n ? rtrim(substr($t, 0, $n - 1)) . '…' : $t; }
function sf_ai_script_first_id(array $rows): int { foreach ($rows as $row) { $id = (int)($row['id'] ?? 0); if ($id > 0) return $id; } return 0; }
function sf_ai_script_find(array $rows, int $id): array { foreach ($rows as $row) if ((int)($row['id'] ?? 0) === $id) return $row; return []; }
function sf_ai_script_card(string $intent, string $type, string $title, string $detail, array $fields = [], bool $canSave = false): array { return ['intent'=>$intent,'type'=>$type,'title'=>$title,'detail'=>$detail,'fields'=>$fields,'can_save'=>$canSave]; }
function sf_ai_script_badge(string $status): string { return sf_admin_status_badge(['draft'=>'draft','ready'=>'active','fix'=>'canceled'][$status] ?? $status); }
function sf_ai_script_has(string $lower, array $terms): bool { foreach ($terms as $term) if ($term !== '' && strpos($lower, strtolower($term)) !== false) return true; return false; }
function sf_ai_script_title(string $prompt, string $fallback = 'AI Draft from Chat'): string { if (preg_match('/\b(?:called|named|titled)\s+([^\,\.\n]{3,90})/i', $prompt, $m)) return trim($m[1]); return $fallback; }
function sf_ai_script_has_explicit_title(string $prompt): bool { return (bool)preg_match('/\b(?:called|named|titled)\s+([^\,\.\n]{3,90})/i', $prompt); }
function sf_ai_script_scene_count(string $prompt): int { $lower = strtolower($prompt); if (preg_match('/\b([0-9]{1,2})\s+(?:scene|scenes|cards|clips)\b/i', $prompt, $m)) return max(1, min(20, (int)$m[1])); foreach (['one'=>1,'two'=>2,'three'=>3,'four'=>4,'five'=>5,'six'=>6,'seven'=>7,'eight'=>8,'nine'=>9,'ten'=>10] as $w=>$n) if (preg_match('/\b'.$w.'\s+(?:scene|scenes|cards|clips)\b/', $lower)) return $n; return 0; }
function sf_ai_script_mentions(string $prompt, array $rows, array $keys): array { $out=[]; $lower=strtolower($prompt); foreach ($rows as $row) foreach ($keys as $key) { $name=trim((string)($row[$key] ?? '')); if ($name !== '' && strpos($lower, strtolower($name)) !== false) { $out[(int)($row['id'] ?? 0)] = $name; break; } } return $out; }
function sf_ai_script_tone(string $prompt): string { $tone=[]; $lower=strtolower($prompt); foreach (['comedy','funny','darker','dark','erotic','romantic','tension','dramatic','reality','scripted','cliffhanger','betrayal','pool','desert','night'] as $h) if (strpos($lower,$h)!==false) $tone[]=$h; return $tone ? implode(', ', array_unique($tone)) : 'AI Script Producer draft'; }
function sf_ai_script_setting_hint(string $prompt): string { $lower=strtolower($prompt); foreach (['pool'=>'Pool','desert'=>'Desert','bar'=>'Bar','backstage'=>'Backstage','stage'=>'Stage','house'=>'House','night'=>'Night','day'=>'Day'] as $needle=>$label) if (strpos($lower,$needle)!==false) return $label; return ''; }
function sf_ai_script_time_hint(string $prompt): string { $lower=strtolower($prompt); if (strpos($lower,'night')!==false) return 'night'; if (strpos($lower,'day')!==false) return 'day'; if (strpos($lower,'sunset')!==false) return 'sunset'; if (strpos($lower,'morning')!==false) return 'morning'; return ''; }
function sf_ai_script_next_number(array $rows, string $key): int { $max=0; foreach ($rows as $row) $max=max($max,(int)($row[$key] ?? 0)); return $max + 1; }
function sf_ai_script_redirect_with_context(int $seasonId, int $episodeId, int $sceneId = 0): void { sf_admin_redirect(sf_url('admin/ai-script-assistant.php?season_id=' . $seasonId . '&episode_id=' . $episodeId . ($sceneId ? '&scene_id=' . $sceneId : ''))); }
function sf_ai_script_first_frame_scene_id(int $storyboardId): int { if (!sf_admin_table_exists('storyboard_scenes') || $storyboardId <= 0) return 0; $row = sf_admin_fetch_one('SELECT id FROM storyboard_scenes WHERE storyboard_id = ? ORDER BY scene_number ASC, id ASC LIMIT 1', [$storyboardId]); return (int)($row['id'] ?? 0); }
function sf_ai_script_current_context(array $request): array {
  $seasons = function_exists('sf_story_v1_seasons') ? sf_story_v1_seasons() : [];
  $allEpisodes = function_exists('sf_story_v1_episodes') ? sf_story_v1_episodes() : [];
  $seasonId = sf_admin_int($request['season_id'] ?? null, 0) ?? 0; if ($seasonId <= 0) $seasonId = (int)($allEpisodes[0]['story_season_id'] ?? sf_ai_script_first_id($seasons));
  $selectedSeason = sf_ai_script_find($seasons, $seasonId) ?: ($seasons[0] ?? []); $seasonId = (int)($selectedSeason['id'] ?? $seasonId);
  $episodes = $seasonId > 0 && function_exists('sf_story_v1_episodes') ? sf_story_v1_episodes($seasonId) : $allEpisodes;
  $episodeId = sf_admin_int($request['episode_id'] ?? null, 0) ?? 0; if ($episodeId <= 0 || !sf_ai_script_find($episodes, $episodeId)) $episodeId = sf_ai_script_first_id($episodes ?: $allEpisodes);
  $selectedEpisode = sf_ai_script_find($episodes, $episodeId) ?: sf_ai_script_find($allEpisodes, $episodeId) ?: ($episodes[0] ?? []); $episodeId = (int)($selectedEpisode['id'] ?? $episodeId);
  $scenes = $episodeId > 0 && function_exists('sf_story_v1_episode_storyboards') ? sf_story_v1_episode_storyboards($episodeId) : [];
  $sceneId = sf_admin_int($request['scene_id'] ?? null, 0) ?? 0; if ($sceneId <= 0 || !sf_ai_script_find($scenes, $sceneId)) $sceneId = sf_ai_script_first_id($scenes);
  $selectedScene = sf_ai_script_find($scenes, $sceneId) ?: ($scenes[0] ?? []);
  $characters = function_exists('sf_story_v1_characters') ? sf_story_v1_characters('active') : [];
  $backgrounds = function_exists('sf_scene_backgrounds_all') ? sf_scene_backgrounds_all() : [];
  $activeBackgrounds = array_values(array_filter($backgrounds, static fn($r) => (string)($r['status'] ?? 'active') === 'active'));
  $assets = function_exists('sf_series_assets_all') ? sf_series_assets_all() : [];
  $activeAssets = array_values(array_filter($assets, static fn($r) => (string)($r['status'] ?? 'active') === 'active'));
  return compact('seasons','allEpisodes','seasonId','selectedSeason','episodes','episodeId','selectedEpisode','scenes','sceneId','selectedScene','characters','activeBackgrounds','activeAssets');
}
function sf_ai_script_generate(string $prompt, array $ctx): array {
  $prompt=trim($prompt); if ($prompt==='') return []; $lower=strtolower($prompt); $title=sf_ai_script_title($prompt); $tone=sf_ai_script_tone($prompt); $charMap=sf_ai_script_mentions($prompt,$ctx['characters'] ?? [],['character_name','name']); $bgMap=sf_ai_script_mentions($prompt,$ctx['activeBackgrounds'] ?? [],['background_name','name','location_label']); $assetMap=sf_ai_script_mentions($prompt,$ctx['activeAssets'] ?? [],['asset_name','name']); $charNames=array_values($charMap); $bgNames=array_values($bgMap); $assetNames=array_values($assetMap); $cards=[]; $sceneCount=sf_ai_script_scene_count($prompt); $selectedSceneId=(int)($ctx['sceneId'] ?? 0);
