  if ($selectedSceneId > 0 && ($charNames || $assetNames || $bgNames || sf_ai_script_has($lower,['assign','add','include','put']))) $cards[]=sf_ai_script_card('assign_continuity','Approved Assignment','Assign continuity to selected scene','Apply detected characters and assets to the selected scene. Background is applied to the first internal frame when available.',['Characters'=>$charNames ? implode(', ',$charNames) : 'none detected','Backgrounds'=>$bgNames ? implode(', ',$bgNames) : 'none detected','Assets'=>$assetNames ? implode(', ',$assetNames) : 'none detected','Save'=>'approved assignment'], true);
  if (sf_ai_script_has($lower,['season'])) $cards[]=sf_ai_script_card('create_season','Approved Create','Season draft: '.$title,'Create a new draft season from the chat prompt.',['Target'=>'story_seasons','Title'=>$title,'Tone hints'=>$tone,'Save'=>'creates a new draft record'], true);
  if (sf_ai_script_has($lower,['episode','epsidoe','ep '])) $cards[]=sf_ai_script_card('create_episode','Approved Create','Episode draft: '.$title,'Create a new draft episode inside the selected season.',['Target'=>'story_episodes','Season'=>sf_ai_script_text($ctx['selectedSeason']['title'] ?? '', 'Select a season'),'Characters'=>$charNames ? implode(', ',$charNames) : 'none detected','Save'=>'creates a new draft record'], true);
  if ($sceneCount > 1) $cards[]=sf_ai_script_card('create_scene','Approved Create','First scene from batch: '.$sceneCount.' scenes','Phase 4 still saves one approved scene at a time; batch execution comes later.',['Target'=>'storyboards / scene cards','Episode'=>sf_ai_script_text($ctx['selectedEpisode']['title'] ?? '', 'Select an episode'),'Scene count requested'=>$sceneCount,'Characters'=>$charNames ? implode(', ',$charNames) : 'use episode cast','Save'=>'creates one new scene shell'], true);
  elseif (sf_ai_script_has($lower,['scene','card','dialogue','beat','cliffhanger','clip','microdrama']) && !($selectedSceneId > 0 && $isUpdate)) $cards[]=sf_ai_script_card('create_scene','Approved Create','Scene card draft','Create a new scene shell tied to the selected episode.',['Target'=>'storyboards / scene cards','Episode'=>sf_ai_script_text($ctx['selectedEpisode']['title'] ?? '', 'Select an episode'),'Characters'=>$charNames ? implode(', ',$charNames) : 'none detected','Backgrounds'=>$bgNames ? implode(', ',$bgNames) : 'none detected','Assets'=>$assetNames ? implode(', ',$assetNames) : 'none detected','Save'=>'creates a new scene shell'], true);
  if (sf_ai_script_has($lower,['character','cast','actor','performer']) || (sf_ai_script_has($lower,['create','add','new']) && sf_ai_script_has($lower,['named','called']))) $cards[]=sf_ai_script_card('create_character','Approved Create','Character profile draft: '.$title,'Create a reusable character profile.',['Target'=>'story_characters','Suggested name'=>$title,'Fields'=>'bio, motivation, personality, relationships, arc','Save'=>'creates a new active character'], true);
  if (sf_ai_script_has($lower,['background','location','pool','desert','stage','room','house','bar','backstage','interior','exterior','night','day']) && !$bgNames) $cards[]=sf_ai_script_card('create_background','Approved Create','Background draft','Create a reusable scene background/location.',['Target'=>'story_scene_backgrounds','Location hint'=>sf_ai_script_setting_hint($prompt) ?: $title,'Save'=>'creates a new active background'], true);
  if (sf_ai_script_has($lower,['asset','prop','vehicle','truck','car','guitar','wardrobe','necklace','chain','document','item']) && !$assetNames) $cards[]=sf_ai_script_card('create_asset','Approved Create','Series asset draft','Create a recurring prop, vehicle, wardrobe piece, document, or continuity item.',['Target'=>'story_series_assets','Detected characters'=>$charNames ? implode(', ',$charNames) : 'none','Save'=>'creates a new active asset'], true);
  if (!$cards) $cards[]=sf_ai_script_card('direction','Draft Direction','Script direction draft','The prompt was captured as creative direction.',['Prompt'=>sf_ai_script_snip($prompt,140),'Next step'=>'Clarify create/update target','Save'=>'disabled'], false);
  return $cards;
}
