<section class="sf-script-layout"><div class="sf-script-panel"><span class="sf-panel-eyebrow">Chat Window</span><div class="sf-script-chat"><div class="sf-script-msg"><span>Assistant</span><strong>I can update and assign selected scene continuity now.</strong><p class="sf-script-copy">Selected context: <?= sf_admin_h(sf_ai_script_text($selectedSeason['title'] ?? '', 'No season')) ?> → <?= sf_admin_h(sf_ai_script_text($selectedEpisode['title'] ?? '', 'No episode')) ?> → <?= sf_admin_h(sf_ai_script_text($selectedScene['title'] ?? '', 'New scene')) ?>.</p></div><?php if ($prompt !== ''): ?><div class="sf-script-msg"><span>You</span><strong><?= sf_admin_h(sf_ai_script_snip($prompt, 180)) ?></strong><p class="sf-script-copy">Generated <?= count($generatedActions) ?> action card(s). Save buttons appear only for approved create/update/assignment actions.</p><div class="sf-script-prompt-meta"><small>Phase 4 updates</small><small>Selected scene only</small><small>No publishing</small></div></div><?php endif; ?><form class="sf-admin-form" method="post"><?= sf_csrf_field() ?><input type="hidden" name="season_id" value="<?= (int)$seasonId ?>"><input type="hidden" name="episode_id" value="<?= (int)$episodeId ?>"><input type="hidden" name="scene_id" value="<?= (int)$sceneId ?>"><label>Ask the AI Script Producer<textarea name="script_prompt" placeholder="Example: Update this scene so it happens at night by the pool, add Mia and Rio, and end with a cliffhanger text message."><?= sf_admin_h($prompt) ?></textarea></label><div class="sf-admin-form-actions"><button type="submit">Generate Action Cards</button></div></form></div></div><aside class="sf-script-panel"><span class="sf-panel-eyebrow">Current Story Context</span><h3><?= sf_admin_h(sf_ai_script_text($selectedEpisode['title'] ?? '', 'No episode selected')) ?></h3><p class="sf-script-copy"><strong>Season:</strong> <?= sf_admin_h(sf_ai_script_text($selectedSeason['title'] ?? '')) ?><br><strong>Episode:</strong> <?= sf_admin_h(sf_ai_script_text($selectedEpisode['title'] ?? '')) ?><br><strong>Scene:</strong> <?= sf_admin_h(sf_ai_script_text($selectedScene['title'] ?? '', 'New scene')) ?></p><p class="sf-script-copy"><strong>Episode outline:</strong><br><?= sf_admin_h(sf_ai_script_snip($selectedEpisode['episode_outline'] ?? $selectedEpisode['synopsis'] ?? $selectedEpisode['logline'] ?? '', 260, 'Episode outline pending.')) ?></p><p class="sf-script-copy"><strong>Model options:</strong><br><?= sf_admin_h(implode(', ', array_values($providerOptions))) ?></p></aside></section>
<section class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow"><?= $generatedActions ? 'Generated Action Cards' : 'Approved Update Actions' ?></span><h2><?= $generatedActions ? 'Review and approve safe actions' : 'What the assistant can update' ?></h2></div></div><div class="sf-script-card-grid"><?php foreach ($draftActions as $card): ?><article class="sf-script-action-card"><?= sf_ai_script_badge('draft') ?><span><?= sf_admin_h($card['type']) ?></span><h3><?= sf_admin_h($card['title']) ?></h3><p class="sf-script-copy"><?= sf_admin_h($card['detail']) ?></p><div class="sf-script-fields"><?php foreach ($card['fields'] as $key => $value): ?><small><?= sf_admin_h($key) ?>: <?= sf_admin_h($value) ?></small><?php endforeach; ?></div><?php if ($generatedActions && !empty($card['can_save'])): ?><form class="sf-script-action-save" method="post"><?= sf_csrf_field() ?><input type="hidden" name="action" value="approve_script_action"><input type="hidden" name="script_intent" value="<?= sf_admin_h($card['intent']) ?>"><input type="hidden" name="script_prompt" value="<?= sf_admin_h($prompt) ?>"><input type="hidden" name="season_id" value="<?= (int)$seasonId ?>"><input type="hidden" name="episode_id" value="<?= (int)$episodeId ?>"><input type="hidden" name="scene_id" value="<?= (int)$sceneId ?>"><button type="submit">Approve & Save</button></form><?php else: ?><p class="sf-script-copy"><small>Draft only.</small></p><?php endif; ?></article><?php endforeach; ?></div></section>
